UPDATE wp_term_taxonomy t
SET t.count = (
  SELECT COUNT(*)
  FROM wp_term_relationships r
  WHERE r.term_taxonomy_id = t.term_taxonomy_id
)
WHERE t.term_taxonomy_id IN (101, 102, 103, 104);

